+private func waitUntilOnMainActor(
+    timeout: Duration = .seconds(1),
+    condition: @escaping @MainActor () -> Bool
+) async {
+    let deadline = ContinuousClock.now + timeout
+    while !(await MainActor.run {
+        condition()
+    }) {
+        XCTAssertLessThan(ContinuousClock.now, deadline)
+        await Task.yield()
+    }
+}
+
+private func makeSettingsStore(
+    suiteName: String,
+    onboardingCompleted: Bool = true
+) -> SettingsStore {
+    let userDefaults = UserDefaults(suiteName: suiteName)!
+    userDefaults.removePersistentDomain(forName: suiteName)
+    let settings = SettingsStore(userDefaults: userDefaults)
+    settings.onboardingCompleted = onboardingCompleted
+    return settings
+}
